class Solution {
    public long smallestNumber(long num) {
        if (num == 0) return 0;

        String str = Math.abs(num) + "";
        char[] chars = str.toCharArray();
        Arrays.sort(chars);

        if (num > 0) {
            for (int i = 0; i < chars.length; i++) {
                if (chars[i] != '0') {
                    char temp = chars[0];
                    chars[0] = chars[i];
                    chars[i] = temp;
                    break;
                }
            }
        }

        long result = Long.parseLong(new String(chars));
        return num < 0 ? -result : result;
    }
}
